import React, { useState } from "react";

const CustomerDashboard = () => {
  const [search, setSearch] = useState("");

  const workers = [
    { id: 1, name: "Ravi", skill: "Plumber", location: "Mysore" },
    { id: 2, name: "Arjun", skill: "Electrician", location: "Nearby" }
  ];

  return (
    <div style={styles.page}>

      {/* TOP BAR */}
      <div style={styles.topbar}>
        <h3>Customer Dashboard</h3>
        <button style={styles.logout}>Logout</button>
      </div>

      <div style={styles.container}>

        {/* SEARCH */}
        <div style={styles.fullCard}>
          <input
            placeholder="Search workers..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={styles.input}
          />
        </div>

        {/* WORKERS */}
        {workers
          .filter(w =>
            w.skill.toLowerCase().includes(search.toLowerCase())
          )
          .map((w) => (
            <div key={w.id} style={styles.card}>
              <h4>{w.name}</h4>
              <p>{w.skill}</p>
              <p>{w.location}</p>

              <button style={styles.hire}>Hire</button>
            </div>
          ))}

      </div>

    </div>
  );
};

export default CustomerDashboard;

/* STYLES */

const styles = {
  page: {
    background: "#f5f6f8",
    minHeight: "100vh",
    fontFamily: "Segoe UI"
  },

  topbar: {
    background: "white",
    padding: "15px 25px",
    display: "flex",
    justifyContent: "space-between",
    borderBottom: "1px solid #e5e7eb"
  },

  container: {
    display: "grid",
    gridTemplateColumns: "repeat(2, 1fr)",
    gap: "15px",
    padding: "20px"
  },

  fullCard: {
    gridColumn: "span 2"
  },

  input: {
    width: "100%",
    padding: "10px",
    borderRadius: "8px",
    border: "1px solid #e5e7eb"
  },

  card: {
    background: "white",
    padding: "15px",
    borderRadius: "12px",
    border: "1px solid #e5e7eb"
  },

  hire: {
    background: "#16a34a",
    color: "white",
    border: "none",
    padding: "8px 12px",
    borderRadius: "8px"
  },

  logout: {
    padding: "8px 14px",
    border: "1px solid #111",
    background: "white",
    borderRadius: "8px"
  }
};
